import{_ as t,o as a,c as o,a1 as r}from"./chunks/framework.BX4nIuL2.js";const p=JSON.parse('{"title":"3D生成器","description":"","frontmatter":{},"headers":[],"relativePath":"tools/threejs-generator/index.md","filePath":"tools/threejs-generator/index.md"}'),l={name:"tools/threejs-generator/index.md"};function i(s,e,n,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_3d生成器" tabindex="-1">3D生成器 <a class="header-anchor" href="#_3d生成器" aria-label="Permalink to &quot;3D生成器&quot;">​</a></h1><p>ProFabX / Sophigo 的在线 3D 预览与报价分析工具，支持多格式导入、装配关系编辑、壁厚风险判断和制造报价估算。</p><p><a href="./app.html" target="_blank" rel="noreferrer">打开 3D生成器</a></p><h2 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to &quot;功能介绍&quot;">​</a></h2><ul><li><strong>多格式载入</strong>：支持 STL / OBJ / STP / STEP / IGES / URDF / F3D / F3Z。</li><li><strong>零件与装配体预览</strong>：单零件、装配体和批量导入均可进入 3D 视图，多零件使用 Google 色系区分。</li><li><strong>报价分析</strong>：保留材质、密度、工艺、后处理、重量、费用统计和 Excel 导出。</li><li><strong>壁厚分析</strong>：提供阈值滑条和红到蓝风险条，用于初步识别制造风险。</li><li><strong>装配关系编辑</strong>：可新增、选中、更新和删除零件之间的固定、转动、直线、平面、球铰关系。</li><li><strong>深色 / 浅色模式</strong>：默认浅色，可在工具右上角切换。</li></ul><h2 id="使用步骤" tabindex="-1">使用步骤 <a class="header-anchor" href="#使用步骤" aria-label="Permalink to &quot;使用步骤&quot;">​</a></h2><ol><li>点击上方链接打开工具页面。</li><li>在左侧选择文件、材质、密度、工艺和后处理。</li><li>在中间 3D 视口选择零件并编辑装配位置。</li><li>在右侧切换“报价分析 / 壁厚分析 / 装配编辑”分页。</li><li>完成后导出 Excel 或生成本地分析快照。</li></ol><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>STL / OBJ 当前可在前端直接解析；URDF 当前解析结构预览；STP / STEP / IGES / F3D / F3Z 会先进入 CAD 待转换状态，后续可接 OpenCascade.js 或服务端 CAD 转换。</p></div>',8)])])}const g=t(l,[["render",i]]);export{p as __pageData,g as default};
